import anthropic, json

client = anthropic.Anthropic()

tools = [
    {
        "name": "get_weather",
        "description": "Get the current weather for a city.",
        "input_schema": {
            "type": "object",
            "properties": {"city": {"type": "string", "description": "City name"}},
            "required": ["city"]
        }
    },
    {
        "name": "get_news",
        "description": "Get recent news headlines for a topic.",
        "input_schema": {
            "type": "object",
            "properties": {"topic": {"type": "string", "description": "News topic"}},
            "required": ["topic"]
        }
    }
]

response = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=512,
    tools=tools,
    messages=[{"role": "user", "content": "What is the weather in London and what is the latest AI news?"}]
)

print(response.stop_reason)   # "tool_use"

# Inspect the parallel calls
for block in response.content:
    if block.type == "tool_use":
        print(f"  {block.name}: {block.input}")
# get_weather: {"city": "London"}
# get_news:    {"topic": "AI"}

print(f"Total tool_use blocks: {sum(1 for b in response.content if b.type == 'tool_use')}")
# 2

# Synchronous execution of parallel tool calls
# Both results go in ONE user message

def get_weather(city: str) -> dict:
    return {"city": city, "temp": 18, "condition": "cloudy"}

def get_news(topic: str) -> list:
    return [{"title": f"AI breakthrough in {topic}", "source": "TechNews"}]

REGISTRY = {"get_weather": get_weather, "get_news": get_news}

# Collect all tool_use blocks
tool_blocks = [b for b in response.content if b.type == "tool_use"]

# Execute sequentially (simple) — still returns all results together
results = []
for block in tool_blocks:
    fn = REGISTRY.get(block.name)
    try:
        output = json.dumps(fn(**block.input)) if fn else json.dumps({"error": "unknown"})
        results.append({"type": "tool_result", "tool_use_id": block.id, "content": output})
    except Exception as e:
        results.append({"type": "tool_result", "tool_use_id": block.id,
                        "content": str(e), "is_error": True})

# Both results in a single user message
messages.append({"role": "assistant", "content": response.content})
messages.append({"role": "user", "content": results})

import asyncio, aiohttp, json

# Async implementations for genuine parallelism
async def get_weather_async(city: str) -> dict:
    async with aiohttp.ClientSession() as session:
        async with session.get(f"https://api.weather.example.com/{city}") as r:
            return await r.json()

async def get_news_async(topic: str) -> list:
    async with aiohttp.ClientSession() as session:
        async with session.get(f"https://api.news.example.com/headlines?q={topic}") as r:
            return await r.json()

ASYNC_REGISTRY = {
    "get_weather": get_weather_async,
    "get_news":    get_news_async,
}

async def execute_parallel(tool_blocks: list) -> list:
    """Execute all tool calls concurrently using asyncio.gather."""
    async def run_one(block):
        fn = ASYNC_REGISTRY.get(block.name)
        if fn is None:
            return {"type": "tool_result", "tool_use_id": block.id,
                    "content": f"Unknown: {block.name}", "is_error": True}
        try:
            result = await fn(**block.input)
            return {"type": "tool_result", "tool_use_id": block.id, "content": json.dumps(result)}
        except Exception as e:
            return {"type": "tool_result", "tool_use_id": block.id, "content": str(e), "is_error": True}

    return await asyncio.gather(*[run_one(b) for b in tool_blocks])

# In an async agent loop
tool_blocks = [b for b in response.content if b.type == "tool_use"]
results = await execute_parallel(tool_blocks)
messages.append({"role": "assistant", "content": response.content})
messages.append({"role": "user", "content": list(results)})

import concurrent.futures, json

def execute_parallel_threaded(tool_blocks: list, registry: dict, timeout: float = 10.0) -> list:
    """Execute tool calls in a thread pool — good for sync I/O-bound tools."""
    results = [None] * len(tool_blocks)

    def run_one(index: int, block):
        fn = registry.get(block.name)
        if fn is None:
            return index, {"type": "tool_result", "tool_use_id": block.id,
                           "content": f"Unknown: {block.name}", "is_error": True}
        try:
            output = fn(**block.input)
            return index, {"type": "tool_result", "tool_use_id": block.id, "content": json.dumps(output)}
        except Exception as e:
            return index, {"type": "tool_result", "tool_use_id": block.id,
                           "content": str(e), "is_error": True}

    with concurrent.futures.ThreadPoolExecutor(max_workers=len(tool_blocks)) as pool:
        futures = [pool.submit(run_one, i, b) for i, b in enumerate(tool_blocks)]
        for future in concurrent.futures.as_completed(futures, timeout=timeout):
            idx, result = future.result()
            results[idx] = result

    return results

# Usage
tool_blocks = [b for b in response.content if b.type == "tool_use"]
results = execute_parallel_threaded(tool_blocks, REGISTRY)
messages.append({"role": "assistant", "content": response.content})
messages.append({"role": "user", "content": results})

import asyncio, traceback

async def safe_call_tool(tool_use) -> dict:
    """Wrap a tool call so it never raises — returns is_error on failure."""
    try:
        result = await call_tool(tool_use.name, tool_use.input)
        return {
            "type": "tool_result",
            "tool_use_id": tool_use.id,
            "content": result,
        }
    except Exception as exc:
        return {
            "type": "tool_result",
            "tool_use_id": tool_use.id,
            "is_error": True,
            "content": f"{type(exc).__name__}: {exc}",
        }

async def execute_all_tools(tool_uses: list) -> list[dict]:
    return await asyncio.gather(*(safe_call_tool(tu) for tu in tool_uses))

# Usage in agent loop
tool_uses = [b for b in response.content if b.type == "tool_use"]
tool_results = asyncio.run(execute_all_tools(tool_uses))

messages.append({"role": "user", "content": tool_results})
